commands.syntax:
DELIMITER //
CREATE FUNCTION nama_func(param tipe, ...)
RETURNS tipe_return
[DETERMINISTIC|NOT DETERMINISTIC]
BEGIN
  DECLARE var tipe;
  -- logic
  RETURN value;
END //
DELIMITER ;

commands.examples:
DELIMITER //
CREATE FUNCTION CalculateDiscount(price DECIMAL(10,2), discount_pct DECIMAL(5,2))
RETURNS DECIMAL(10,2)
DETERMINISTIC
BEGIN
  RETURN price - (price * discount_pct / 100);
END //
DELIMITER ;

-- Penggunaan
SELECT name, price, CalculateDiscount(price, 10) AS discounted_price FROM products;

-- Function dengan logika
DELIMITER //
CREATE FUNCTION GetUserLevel(total_spent DECIMAL(12,2))
RETURNS VARCHAR(20)
DETERMINISTIC
BEGIN
  IF total_spent >= 10000000 THEN RETURN 'Platinum';
  ELSEIF total_spent >= 5000000 THEN RETURN 'Gold';
  ELSEIF total_spent >= 1000000 THEN RETURN 'Silver';
  ELSE RETURN 'Bronze';
  END IF;
END //
DELIMITER ;

DROP FUNCTION CalculateDiscount;
DROP FUNCTION IF EXISTS GetUserLevel;
